function buildDashboardReportGroups(){const unresolved=new Map(),groups=[];for(const report of [...dashboardReports].sort((a,b)=>new Date(b.created_at)-new Date(a.created_at))){if(report.status==='resolved'){groups.push({key:`report:${report.id}`,reports:[report]});continue}const key=dashboardReportGroupKey(report);if(!unresolved.has(key)){const group={key,reports:[]};unresolved.set(key,group);groups.push(group)}unresolved.get(key).reports.push(report)}return groups}
function renderDashboardReports(){const direction=dashboardReportSort.direction==='asc'?1:-1,groups=buildDashboardReportGroups().sort((a,b)=>{const firstA=a.reports[0],firstB=b.reports[0];let value=0;if(dashboardReportSort.key==='item')value=dashboardReportItem(firstA).localeCompare(dashboardReportItem(firstB),undefined,{sensitivity:'base'});else if(dashboardReportSort.key==='status')value=Number(firstA.status==='resolved')-Number(firstB.status==='resolved');else value=new Date(firstA.created_at).getTime()-new Date(firstB.created_at).getTime();return value?value*direction:new Date(firstB.created_at).getTime()-new Date(firstA.created_at).getTime()});renderedDashboardReportGroups=groups;$$('[data-report-sort-heading]').forEach(th=>th.setAttribute('aria-sort',th.dataset.reportSortHeading===dashboardReportSort.key?(dashboardReportSort.direction==='asc'?'ascending':'descending'):'none'));$$('[data-dashboard-report-sort]').forEach(button=>{const active=button.dataset.dashboardReportSort===dashboardReportSort.key;button.classList.toggle('active',active);button.querySelector('.sort-arrow').textContent=active?(dashboardReportSort.direction==='asc'?'↑':'↓'):''});const groupedCount=groups.filter(group=>group.reports.length>1).length;$('#dashboardReportCount').textContent=`${dashboardReports.length} open report${dashboardReports.length===1?'':'s'}${groupedCount?` · ${groupedCount} grouped`:''}`;$('#dashboardReports').innerHTML=groups.map((group,index)=>{const x=group.reports[0],p=x.playback||{},title=p.seriesName||p.itemName||'Unknown item',subtitle=p.seriesName?p.itemName:(p.itemType||'Unknown type'),isGrouped=group.reports.length>1,submitters=[...new Set(group.reports.map(report=>report.username))],expanded=isGrouped&&expandedDashboardReportGroups.has(group.key),issues=[...new Set(group.reports.map(report=>report.issue_detail||report.issue_type))],details=isGrouped?`<tr id="dashboard-report-group-${index}" class="grouped-report-row ${expanded?'':'hidden'}"><td colspan="5"><div class="report-group-details">${group.reports.map(report=>`<div class="report-group-entry"><b>${esc(report.username)}</b><span>${new Date(report.created_at).toLocaleString()}</span><span><span class="tag">${esc(report.issue_type)}</span> ${esc(report.issue_detail||'Legacy report')}</span><button type="button" class="secondary" onclick="openDashboardReport(${Number(report.id)})">View details</button></div>`).join('')}</div></td></tr>`:'';return`<tr><td class="dashboard-report-item"><b>${esc(title)}</b><br><small>${esc(subtitle)}</small><br><small>${isGrouped?`Submitted by ${submitters.map(esc).join(', ')} · newest first`:`Submitted by ${esc(x.username)}`}</small></td><td>${new Date(x.created_at).toLocaleString()}${isGrouped?'<br><small>Most recent</small>':''}</td><td>${isGrouped?`<b>${group.reports.length} unresolved reports</b><br><small>${issues.map(esc).join(' · ')}</small>`:`<span class="tag">${esc(x.issue_type)}</span><br><small>${esc(x.issue_detail||'Legacy report')}</small>`}</td><td><span class="report-status ${x.status==='resolved'?'resolved':'open'}">${isGrouped?`${group.reports.length} open`:esc(x.status)}</span></td><td>${isGrouped?`<button type="button" class="secondary" aria-expanded="${expanded}" aria-controls="dashboard-report-group-${index}" onclick="toggleDashboardReportGroup(${index})">${expanded?'Hide details':'More details'} ${expanded?'↑':'↓'}</button>`:`<button type="button" class="secondary" onclick="openDashboardReport(${Number(x.id)})">View details</button>`}</td></tr>${details}`}).join('')||'<tr><td colspan="5">No unresolved reports. Everything is caught up.</td></tr>'}
window.toggleDashboardReportGroup=index=>{const group=renderedDashboardReportGroups[Number(index)];if(!group||group.reports.length<2)return;if(expandedDashboardReportGroups.has(group.key))expandedDashboardReportGroups.delete(group.key);else expandedDashboardReportGroups.add(group.key);renderDashboardReports()};
function setDashboardReportSort(key){if(dashboardReportSort.key===key)dashboardReportSort.direction=dashboardReportSort.direction==='asc'?'desc':'asc';else dashboardReportSort={key,direction:key==='time'?'desc':'asc'};renderDashboardReports()}
window.openDashboardReport=async id=>{try{const {report}=await api(`/api/admin/reports/${encodeURIComponent(id)}`);adminIssues=adminIssues.filter(x=>Number(x.id)!==Number(id));adminIssues.push(report);openReportDetails(id)}catch(x){alert(x.message)}};
async function loadAdmin(){const d=await api('/api/admin/dashboard');dashboardReports=Array.isArray(d.reports)?d.reports:[];$('#viewerCount').textContent=d.viewers.length;$('#openCount').textContent=d.openReports;drawOverviewDiagnostics(d.metrics);renderDashboardReports();$('#overviewUpdated').textContent=`Live · ${new Date().toLocaleTimeString([],{hour:'numeric',minute:'2-digit',second:'2-digit'})}`;$('#overviewViewers').innerHTML=d.viewers.length?d.viewers.map(x=>`<div class="playback"><b>${esc(x.username)}</b><br>${x.payload.seriesName?`${esc(x.payload.seriesName)} · `:''}${esc(x.payload.itemName)}<br><small>${esc(x.payload.device||'Unknown device')} · ${esc(x.payload.client||'Unknown client')}</small>${playbackProgress(x.payload)}</div>`).join(''):'<p class="sub">Nobody is actively watching right now.</p>'}
async function refreshAdmin(){if(adminRefreshInFlight)return;adminRefreshInFlight=true;try{await loadAdmin();if(!$('#reportsPage').classList.contains('hidden'))await loadAllReports();if(!$('#userReports').classList.contains('hidden'))await loadAdminReports()}catch(x){console.warn('Admin refresh failed:',x)}finally{adminRefreshInFlight=false}}
function startAdminRefresh(){if(adminRefreshTimer)return;adminRefreshTimer=setInterval(()=>{if(!document.hidden)refreshAdmin()},10_000);document.addEventListener('visibilitychange',()=>{if(!document.hidden)refreshAdmin()})}

function setupAdmin(){setupReportDetails();setupResolutionEditor();setupAccessLinks();setupUserInvites();setupNotifications();configureModal('#notificationModal',window.closeNotificationEditor);$$('[data-dashboard-report-sort]').forEach(button=>button.onclick=()=>setDashboardReportSort(button.dataset.dashboardReportSort));$$('[data-all-reports-sort]').forEach(button=>button.onclick=()=>setAllReportsSort(button.dataset.allReportsSort));$('#openReportsShortcut').onclick=()=>navigate('reportsPage');$('#allReportsSort').onchange=renderAllReports;$('#allReportsDirection').onchange=renderAllReports;$('#linkForm').onsubmit=createAccessLink;$('#userInviteAdminForm').onsubmit=createUserInvite;$('#inviteShortcut').onclick=()=>selectTab('users','userInvitesTab');$('#historyUser').onchange=loadWatchHistory;$('#jellyfinSettingsForm').onsubmit=saveJellyfinSettings}
async function loadUsers(){try{const d=await api('/api/admin/users');$('#userCards').innerHTML=d.users.map(u=>`<div class="playback user-card"><b><span class="status-dot ${u.disabled?'disabled':''}"></span>${esc(u.username)}</b>${u.isAdministrator?' <span class="tag">Jellyfin admin</span>':''}<p class="sub">${u.recent?`Most recent: ${u.recent.seriesName?`${esc(u.recent.seriesName)} · `:''}${esc(u.recent.itemName)}<br><small>${new Date(u.recent.lastSeen).toLocaleString()}</small>`:'No playback observed yet.'}</p><p><small>Most watched: <b>${esc(u.favorite||'Not enough history yet')}</b></small></p><div class="statline"><small>${formatDuration(u.observedSeconds)} observed</small><small>${u.watchEntries} watch sessions</small><small>${u.openReports} open / ${u.reports} reports</small></div></div>`).join('')||'<p class="sub">No Jellyfin users found.</p>';const options='<option value="">All users</option>'+d.users.map(u=>`<option value="${esc(u.id)}">${esc(u.username)}</option>`).join('');$('#historyUser').innerHTML=options;$('#linkUser').innerHTML=d.users.filter(u=>!u.disabled).map(u=>`<option value="${esc(u.id)}">${esc(u.username)}</option>`).join('')}catch(x){$('#userCards').innerHTML=`<div class="notice error">${esc(x.message)}</div>`}}
async function loadWatchHistory(){try{const id=$('#historyUser').value,d=await api('/api/admin/watch-history'+(id?`?userId=${encodeURIComponent(id)}`:''));$('#historyRows').innerHTML=d.history.map(h=>`<tr><td>${new Date(h.last_seen).toLocaleString()}<br><small>Started ${new Date(h.started_at).toLocaleString()}</small></td><td>${esc(h.username)}</td><td><b>${h.payload?.seriesName?`${esc(h.payload.seriesName)} · `:''}${esc(h.payload?.itemName||'Unknown item')}</b><br><small>${esc(h.payload?.itemType||'Unknown type')} · ${esc(h.payload?.device||'Unknown device')}</small></td><td>${formatDuration(h.observed_seconds)}</td><td>${playbackProgress(h.payload)}</td></tr>`).join('')||'<tr><td colspan="5">No watch history has been observed yet.</td></tr>'}catch(x){$('#historyRows').innerHTML=`<tr><td colspan="5">${esc(x.message)}</td></tr>`}}
function allReportSortValue(report,key){const p=report.playback||{};if(key==='time')return new Date(report.created_at).getTime();if(key==='title')return p.seriesName||p.itemName||'';if(key==='season')return p.seasonName||'';if(key==='item')return p.itemName||'';if(key==='user')return report.username||'';return report.issue_type||''}
function setAllReportsSort(key){const sort=$('#allReportsSort'),direction=$('#allReportsDirection');if(sort.value===key)direction.value=direction.value==='asc'?'desc':'asc';else{sort.value=key;direction.value=key==='time'?'desc':'asc'}renderAllReports()}
function renderAllReports(){const key=$('#allReportsSort').value,directionValue=$('#allReportsDirection').value,direction=directionValue==='asc'?1:-1,reports=[...allReports].sort((a,b)=>{const status=Number(a.status==='resolved')-Number(b.status==='resolved');if(status)return status;const first=allReportSortValue(a,key),second=allReportSortValue(b,key),value=key==='time'?first-second:String(first).localeCompare(String(second),undefined,{numeric:true,sensitivity:'base'});return value?value*direction:new Date(b.created_at).getTime()-new Date(a.created_at).getTime()}),open=allReports.filter(report=>report.status!=='resolved').length;$$('[data-all-report-sort-heading]').forEach(th=>th.setAttribute('aria-sort',th.dataset.allReportSortHeading===key?(directionValue==='asc'?'ascending':'descending'):'none'));$$('[data-all-reports-sort]').forEach(button=>{const active=button.dataset.allReportsSort===key;button.classList.toggle('active',active);button.querySelector('.sort-arrow').textContent=active?(directionValue==='asc'?'↑':'↓'):''});$('#allReportsCount').textContent=`${open} open · ${allReports.length-open} resolved`;$('#allReports').innerHTML=reports.map(x=>{const p=x.playback||{},title=p.seriesName||p.itemName||'Unknown item';return`<tr><td><span class="report-status ${x.status==='resolved'?'resolved':'open'}">${esc(x.status)}</span></td><td><b>${esc(title)}</b><br><small>${esc(p.itemType||'Unknown type')}</small></td><td>${esc(p.seasonName||'—')}</td><td>${esc(p.itemName||'Unknown item')}</td><td>${new Date(x.created_at).toLocaleString()}</td><td>${esc(x.username)}</td><td><span class="tag">${esc(x.issue_type)}</span><br><small>${esc(x.issue_detail||'Legacy report')}</small></td><td><button type="button" class="secondary" onclick="openDashboardReport(${Number(x.id)})">View details</button></td></tr>`}).join('')||'<tr><td colspan="8">No reports have been submitted yet.</td></tr>'}
async function loadAllReports(){try{const d=await api('/api/admin/reports');allReports=d.reports;renderAllReports()}catch(x){$('#allReports').innerHTML=`<tr><td colspan="8">${esc(x.message)}</td></tr>`}}
async function loadAdminReports(){try{const d=await api('/api/admin/reports');adminIssues=d.reports;$('#issues').innerHTML=d.reports.map(x=>`<tr><td>${new Date(x.created_at).toLocaleString()}</td><td><b>${esc(x.username)}</b><br>${esc(x.playback?.itemName||'Unknown item')}</td><td><span class="tag">${esc(x.issue_type)}</span><br><small>${esc(x.issue_detail||x.description||'Legacy report')}</small></td><td><span class="${x.status==='resolved'?'resolved':'open'}">${esc(x.status)}</span></td><td><button class="secondary" onclick="openDashboardReport(${x.id})">View more info</button></td></tr>`).join('')||'<tr><td colspan="5">No reports yet.</td></tr>'}catch(x){$('#issues').innerHTML=`<tr><td colspan="5">${esc(x.message)}</td></tr>`}}

function setupReportDetails(){if($('#reportDetailModal'))return;document.body.insertAdjacentHTML('beforeend','<div id="reportDetailModal" class="modal-overlay hidden" role="dialog" aria-modal="true" aria-labelledby="reportDetailTitle" onclick="handleModalBackdrop(event,closeReportDetails)"><div class="panel modal-shell modal-shell-wide"><div class="modal-header"><h2 id="reportDetailTitle">Report details</h2><button type="button" class="secondary modal-close" onclick="closeReportDetails()">Close</button></div><div id="reportDetailBody"></div><div id="reportDetailActions" style="display:flex;gap:10px;flex-wrap:wrap;margin-top:18px"></div></div></div>')}
function metricValues(metrics,key,transform=v=>v){return metrics.map(m=>m[key]).filter(v=>v!==null&&v!==undefined).map(v=>transform(Number(v))).filter(Number.isFinite)}
function metricSummary(values){return values.length?{average:values.reduce((s,n)=>s+n,0)/values.length,peak:Math.max(...values),latest:values.at(-1)}:null}
function formatBytes(bytes){const value=Number(bytes);if(!Number.isFinite(value)||value<=0)return'Unavailable';const units=['B','KB','MB','GB','TB'],i=Math.min(units.length-1,Math.floor(Math.log(value)/Math.log(1024)));return`${(value/1024**i).toFixed(i>2?1:0)} ${units[i]}`}
function diagnosticHtml(metrics){const cpu=metricSummary(metricValues(metrics,'cpu_percent')),ramValues=metrics.map(m=>{const used=Number(m.memory_bytes),limit=Number(m.memory_limit);return used>=0&&limit>0?used/limit*100:null}).filter(Number.isFinite),ram=metricSummary(ramValues),gpu=metricSummary(metricValues(metrics,'gpu_percent')),latest=metrics.at(-1)||{},vendor=[...metrics].reverse().find(m=>m.gpu_vendor)?.gpu_vendor||'GPU',streams=Array.isArray(latest.transcode_details)?latest.transcode_details:[],stat=(name,data,extra='')=>`<div class="metric"><small>${esc(name)}</small><b style="font-size:1.05rem">${data?`${data.average.toFixed(1)}% avg · ${data.peak.toFixed(1)}% peak`:'Unavailable'}</b>${extra?`<small>${esc(extra)}</small>`:''}</div>`,streamCards=streams.map(s=>`<div class="playback"><b>${esc(s.username)} · ${esc(s.seriesName?`${s.seriesName} · ${s.itemName}`:s.itemName)}</b><br><span class="tag">${esc(s.mode)}</span><br><small>${[s.videoCodec,s.audioCodec,s.container,s.width&&s.height?`${s.width}×${s.height}`:null,s.bitrate?`${(Number(s.bitrate)/1_000_000).toFixed(1)} Mbps`:null,s.framerate?`${Number(s.framerate).toFixed(1)} fps`:null,s.completionPercentage!=null?`${Number(s.completionPercentage).toFixed(0)}% complete`:null,s.hardwareAccelerationType?`${s.hardwareAccelerationType} acceleration`:null].filter(Boolean).map(esc).join(' · ')}</small>${Array.isArray(s.reasons)&&s.reasons.length?`<br><small>Reasons: ${esc(s.reasons.join(', '))}</small>`:''}</div>`).join('');return`<h3>Server resources · five minutes before report</h3><div class="grid">${stat('CPU',cpu)}${stat('RAM',ram,latest.memory_bytes?`${formatBytes(latest.memory_bytes)} at latest sample`:'')}${stat(vendor,gpu)}</div><div style="margin-top:12px"><small><span style="color:#a78bfa">● CPU</span> · <span style="color:#22d3ee">● RAM</span> · <span style="color:#4ade80">● ${esc(vendor)}</span></small><canvas id="reportResourceChart" style="width:100%;height:220px"></canvas></div><h3>Playback pipeline · five minutes before report</h3><div><small><span style="color:#22d3ee">● Direct play</span> · <span style="color:#ffd586">● Remux</span> · <span style="color:#fb7185">● Transcode</span></small><canvas id="reportTranscodeChart" style="width:100%;height:220px"></canvas></div><h3>Latest active stream details</h3><div class="grid">${streamCards||'<p class="sub">No active streams were recorded in the latest sample.</p>'}</div>`}
function drawDiagnosticChart(canvas,metrics,lines,fixedMax,endLabel='report'){const ctx=canvas.getContext('2d'),ratio=devicePixelRatio,W=canvas.clientWidth||800,H=220;canvas.width=W*ratio;canvas.height=H*ratio;ctx.scale(ratio,ratio);ctx.clearRect(0,0,W,H);const all=lines.flatMap(line=>line.values.filter(Number.isFinite));if(!all.length){ctx.fillStyle='#aeb8cc';ctx.fillText('No telemetry was available for this period.',12,28);return}const max=Math.max(fixedMax||1,...all),left=34,right=10,top=12,bottom=28,plotW=W-left-right,plotH=H-top-bottom;ctx.strokeStyle='#303b59';ctx.fillStyle='#aeb8cc';ctx.font='12px system-ui';for(let i=0;i<=4;i++){const y=top+plotH*i/4;ctx.beginPath();ctx.moveTo(left,y);ctx.lineTo(W-right,y);ctx.stroke();ctx.fillText(String(Math.round(max*(1-i/4))),2,y+4)}ctx.fillText('−5m',left,H-7);ctx.fillText(endLabel,Math.max(left,W-right-(endLabel.length*7)),H-7);for(const line of lines){ctx.strokeStyle=line.color;ctx.lineWidth=2.5;ctx.beginPath();let drawing=false;line.values.forEach((v,i)=>{if(!Number.isFinite(v)){drawing=false;return}const x=left+(metrics.length===1?plotW:plotW*i/(metrics.length-1)),y=top+plotH-(Math.min(max,Math.max(0,v))/max*plotH);if(drawing)ctx.lineTo(x,y);else{ctx.moveTo(x,y);drawing=true}});ctx.stroke()}}
function drawReportDiagnostics(metrics){const cpu=metrics.map(m=>m.cpu_percent==null?null:Number(m.cpu_percent)),ram=metrics.map(m=>{const used=Number(m.memory_bytes),limit=Number(m.memory_limit);return used>=0&&limit>0?used/limit*100:null}),gpu=metrics.map(m=>m.gpu_percent==null?null:Number(m.gpu_percent));drawDiagnosticChart($('#reportResourceChart'),metrics,[{values:cpu,color:'#a78bfa'},{values:ram,color:'#22d3ee'},{values:gpu,color:'#4ade80'}],100);const direct=metrics.map(m=>m.direct_play_count==null?null:Number(m.direct_play_count)),remux=metrics.map(m=>m.remux_count==null?null:Number(m.remux_count)),transcode=metrics.map(m=>m.transcode_count==null?null:Number(m.transcode_count));drawDiagnosticChart($('#reportTranscodeChart'),metrics,[{values:direct,color:'#22d3ee'},{values:remux,color:'#ffd586'},{values:transcode,color:'#fb7185'}])}
window.openReportDetails=id=>{const x=adminIssues.find(r=>Number(r.id)===Number(id));if(!x)return;const p=x.playback||{},recent=p.source==='recent',manual=p.source==='manual',metrics=Array.isArray(x.metrics)?x.metrics:[],delivery=x.status==='resolved'?(x.popup_delivered_at?`Jellyfin popup sent ${new Date(x.popup_delivered_at).toLocaleString()}`:x.popup_error?`Popup retry pending: ${x.popup_error}`:x.notification_queued_at?'Popup queued for a compatible Jellyfin session':'Resolved before popup delivery was enabled'):'';$('#reportDetailTitle').textContent=`Report #${x.id}`;$('#reportDetailBody').innerHTML=`<div class="playback" style="margin-top:18px"><b>${p.seriesName?`${esc(p.seriesName)} · `:''}${esc(p.itemName||'Unknown item')}</b><br><small>${esc(p.itemType||'Unknown type')} · ${esc(p.device||'Unknown device')} · ${esc(p.client||'Unknown client')}</small>${playbackProgress(p)}</div><div class="grid" style="margin-top:14px"><div class="metric"><small>User</small><b style="font-size:1.05rem">${esc(x.username)}</b></div><div class="metric"><small>Submitted</small><b style="font-size:1.05rem">${new Date(x.created_at).toLocaleString()}</b></div><div class="metric"><small>Playback source</small><b style="font-size:1.05rem">${esc(playbackSourceText(p))}</b></div></div><h3 style="margin-bottom:5px">What they reported</h3><p><span class="tag">${esc(x.issue_type)}</span></p><div class="notice" style="background:#222944"><b>${esc(x.issue_detail||'Legacy report')}</b>${x.description?`<br><br>${esc(x.description)}`:'<br><small>No additional description was provided.</small>'}</div><p><small>${recent&&p.lastSeen?`Last observed ${new Date(p.lastSeen).toLocaleString()} · `:''}${manual?'Playback position was not captured because the item was selected manually.':`Playback position ${esc(formatTicks(p.positionTicks))}`}</small></p>${diagnosticHtml(metrics)}${x.resolution_note?`<div class="notice success"><b>Resolution</b><br>${esc(x.resolution_note)}${delivery?`<br><small>${esc(delivery)}</small>`:''}</div>`:''}`;$('#reportDetailActions').innerHTML=x.status==='open'?`<button style="width:auto;margin:0" onclick="resolveFromDetail(${x.id})">Resolve report</button>`:`<button class="secondary" onclick="reopenFromDetail(${x.id})">Reopen report</button>`;openModal('#reportDetailModal');requestAnimationFrame(()=>drawReportDiagnostics(metrics))};
window.closeReportDetails=()=>closeModal('#reportDetailModal');window.resolveFromDetail=id=>{closeReportDetails();openResolutionEditor(id)};window.reopenFromDetail=async id=>{closeReportDetails();await reopenIssue(id)};

function setupResolutionEditor(){if($('#resolutionModal'))return;document.body.insertAdjacentHTML('beforeend','<div id="resolutionModal" class="modal-overlay hidden" role="dialog" aria-modal="true" aria-labelledby="resolutionTitle" onclick="handleModalBackdrop(event,closeResolutionEditor)"><div class="panel modal-shell"><div class="modal-header"><h2 id="resolutionTitle">Resolve report</h2><button type="button" class="secondary modal-close" onclick="closeResolutionEditor()">Close</button></div><p class="sub" id="resolutionContext"></p><form id="resolutionForm"><label>Resolution note <small>(optional)</small></label><textarea name="resolutionNote" maxlength="2000" placeholder="For example: Replaced the damaged media file and verified playback."></textarea><small>This note appears in My Reports and in the queued Jellyfin popup.</small><button>Mark resolved and notify user</button></form><div id="resolutionMessage"></div></div></div>');$('#resolutionForm').onsubmit=resolveIssue}
window.openResolutionEditor=id=>{const issue=adminIssues.find(x=>Number(x.id)===Number(id));if(!issue)return;const form=$('#resolutionForm');form.dataset.id=String(id);form.reset();$('#resolutionContext').textContent=`Report #${id} · ${issue.username} · ${issue.playback?.itemName||'Unknown item'}`;$('#resolutionMessage').innerHTML='';openModal('#resolutionModal')};window.closeResolutionEditor=()=>closeModal('#resolutionModal');
async function resolveIssue(e){e.preventDefault();const form=e.target;try{await api('/api/admin/issues/'+form.dataset.id,{method:'PATCH',body:JSON.stringify({status:'resolved',resolutionNote:form.elements.namedItem('resolutionNote').value})});closeResolutionEditor();await Promise.all([refreshAdmin(),loadMyReports(),loadAdminReports()])}catch(x){msg('#resolutionMessage',x.message,true)}}
window.reopenIssue=async id=>{if(!confirm('Reopen this report? Any queued resolution popup will be cancelled.'))return;await api('/api/admin/issues/'+id,{method:'PATCH',body:JSON.stringify({status:'open'})});await Promise.all([refreshAdmin(),loadMyReports(),loadAdminReports()])};

function setupAccessLinks(){}
function setupUserInvites(){}
async function loadUserInvites(){try{const d=await api('/api/admin/user-invites');$('#userInvites').innerHTML=d.invites.map(i=>`<tr><td><b>${esc(i.label)}</b><br><small>Created ${new Date(i.created_at).toLocaleString()}</small></td><td>${new Date(i.expires_at).toLocaleString()}</td><td><button class="secondary" onclick="revokeUserInvite('${esc(i.id)}')">Revoke</button></td></tr>`).join('')||'<tr><td colspan="3">No active invitations.</td></tr>'}catch(x){msg('#userInviteResult',x.message,true)}}
async function createUserInvite(e){e.preventDefault();const body=Object.fromEntries(new FormData(e.target));body.durationMinutes=Number(body.durationMinutes);try{const d=await api('/api/admin/user-invites',{method:'POST',body:JSON.stringify(body)}),url=location.origin+d.path;$('#userInviteResult').innerHTML=`<div class="notice success"><b>Copy this invitation now.</b> It is shown once and disappears after successful use.<input id="createdUserInvite" readonly value="${esc(url)}"><button type="button" class="secondary" onclick="copyUserInvite()">Copy invitation</button></div>`;e.target.reset();loadUserInvites()}catch(x){msg('#userInviteResult',x.message,true)}}
window.copyUserInvite=async()=>copyInput('#createdUserInvite');window.revokeUserInvite=async id=>{if(!confirm('Revoke this invitation?'))return;await api('/api/admin/user-invites/'+id,{method:'DELETE'});loadUserInvites()};
async function loadAccessLinks(){try{const d=await api('/api/admin/access-links');$('#linkUser').innerHTML=d.users.map(u=>`<option value="${esc(u.id)}">${esc(u.username)}</option>`).join('');$('#accessLinks').innerHTML=d.links.map(l=>`<tr><td><b>${esc(l.username)}</b><br><small>${esc(l.label)}</small></td><td>${l.revoked_at?'<span class="resolved">Revoked</span>':l.expires_at?new Date(l.expires_at).toLocaleDateString():'Never'}</td><td>${l.last_used_at?new Date(l.last_used_at).toLocaleString():'Never'}</td><td>${l.revoked_at?'':`<button class="secondary" onclick="revokeLink('${esc(l.id)}')">Revoke</button>`}</td></tr>`).join('')||'<tr><td colspan="4">No private links created.</td></tr>'}catch(x){msg('#linkResult',x.message,true)}}
async function createAccessLink(e){e.preventDefault();const body=Object.fromEntries(new FormData(e.target));body.expiresDays=Number(body.expiresDays);try{const d=await api('/api/admin/access-links',{method:'POST',body:JSON.stringify(body)}),url=location.origin+d.path;$('#linkResult').innerHTML=`<div class="notice success"><b>Copy this link now.</b> JellyPulse cannot show its secret again.<input id="createdLink" readonly value="${esc(url)}"><button type="button" class="secondary" onclick="copyCreatedLink()">Copy link</button></div>`;e.target.reset();loadAccessLinks()}catch(x){msg('#linkResult',x.message,true)}}
async function copyInput(selector){const input=$(selector);input.select();try{if(navigator.clipboard)await navigator.clipboard.writeText(input.value);else document.execCommand('copy')}catch{document.execCommand('copy')}}window.copyCreatedLink=async()=>copyInput('#createdLink');window.revokeLink=async id=>{if(!confirm('Revoke this link? Anyone using it will no longer be able to sign in.'))return;await api('/api/admin/access-links/'+id,{method:'DELETE'});loadAccessLinks()};

async function loadSettings(){try{const d=await api('/api/admin/settings');$('#settingsHost').value=d.host}catch(x){msg('#jellyfinSettingsMessage',x.message,true)}}
async function saveJellyfinSettings(e){e.preventDefault();try{const d=await api('/api/admin/settings/jellyfin',{method:'PUT',body:JSON.stringify(Object.fromEntries(new FormData(e.target)))});e.target.apiKey.value='';e.target.adminPassword.value='';msg('#jellyfinSettingsMessage',`Connected to ${d.serverName}. Jellyfin configuration updated.`);refreshAdmin()}catch(x){msg('#jellyfinSettingsMessage',x.message,true)}}

const notificationFieldTemplates={discord:'<label>Discord webhook URL</label><input name="webhookUrl" type="url" required>',slack:'<label>Slack incoming webhook URL</label><input name="webhookUrl" type="url" required>',home_assistant:'<label>Home Assistant URL</label><input name="baseUrl" type="url" placeholder="https://home.example.com" required><label>Long-lived access token</label><input name="accessToken" type="password" required><label>Notify service</label><input name="notifyService" placeholder="mobile_app_your_phone" pattern="[a-z0-9_]+" required>',email:'<label>SMTP host</label><input name="host" required><label>SMTP port</label><input name="port" type="number" value="587" min="1" max="65535" required><label><input name="secure" type="checkbox" style="width:auto"> Use implicit TLS (usually port 465)</label><label>SMTP username</label><input name="username"><label>SMTP password</label><input name="password" type="password"><label>From address</label><input name="from" type="email" required><label>Recipient address(es)</label><input name="to" placeholder="admin@example.com" required>',ntfy:'<label>ntfy server URL</label><input name="serverUrl" type="url" value="https://ntfy.sh" required><label>Topic</label><input name="topic" pattern="[A-Za-z0-9_-]+" required><label>Access token (optional)</label><input name="accessToken" type="password">',gotify:'<label>Gotify URL</label><input name="baseUrl" type="url" required><label>Application token</label><input name="appToken" type="password" required>',telegram:'<label>Telegram bot token</label><input name="botToken" type="password" required><label>Chat ID</label><input name="chatId" required>',pushover:'<label>Application token</label><input name="appToken" type="password" required><label>User/group key</label><input name="userKey" type="password" required>',webhook:'<label>Webhook URL</label><input name="webhookUrl" type="url" required>',apprise:'<label>Apprise API URL</label><input name="serverUrl" type="url" placeholder="http://apprise-api:8000" required><label>Apprise notification URL(s)</label><textarea name="urls" placeholder="mailto://... or discord://..." required></textarea>'};
function setupNotifications(){const panel=$('#notificationPanel');panel.innerHTML='<h3>Notification destinations</h3><p class="sub">Send every new issue to one or more services. Credentials are encrypted at rest.</p><form id="notificationForm"><label>Destination name</label><input name="label" placeholder="My phone" maxlength="80" required><label>Provider</label><select name="type" id="notificationType"><option value="home_assistant">Home Assistant</option><option value="email">Email (SMTP)</option><option value="discord">Discord</option><option value="slack">Slack</option><option value="ntfy">ntfy</option><option value="gotify">Gotify</option><option value="telegram">Telegram</option><option value="pushover">Pushover</option><option value="webhook">Generic webhook</option><option value="apprise">Apprise API</option></select><div id="notificationFields"></div><button>Add destination</button></form><div id="notificationMessage"></div><div class="table-wrap"><table><thead><tr><th>Destination</th><th>Status</th><th>Last sent</th><th></th></tr></thead><tbody id="notificationDestinations"></tbody></table></div>';if(!$('#notificationModal'))document.body.insertAdjacentHTML('beforeend','<div id="notificationModal" class="hidden" role="dialog" aria-modal="true" style="position:fixed;inset:0;background:#000b;z-index:1000;display:flex;align-items:center;justify-content:center;padding:20px"><div class="panel" style="width:min(600px,100%);max-height:90vh;overflow:auto;margin:0"><div style="display:flex;justify-content:space-between;align-items:center"><h2 style="margin:0">Edit notification destination</h2><button type="button" class="secondary" onclick="closeNotificationEditor()">Close</button></div><p class="sub" id="editProvider"></p><form id="editNotificationForm"><input name="type" id="editNotificationType" type="hidden"><label>Destination name</label><input name="label" id="editNotificationLabel" maxlength="80" required><div id="editNotificationFields"></div><button>Save changes</button></form><div id="editNotificationMessage"></div></div></div>');$('#notificationType').onchange=renderNotificationFields;renderNotificationFields();$('#notificationForm').onsubmit=createNotification;$('#editNotificationForm').onsubmit=saveNotification}
function renderNotificationFields(){$('#notificationFields').innerHTML=notificationFieldTemplates[$('#notificationType').value]}function notificationConfig(form){const d=Object.fromEntries(new FormData(form)),type=d.type;delete d.label;delete d.type;if(type==='email'){d.port=Number(d.port);d.secure=form.secure.checked}return{type,...d}}
async function createNotification(e){e.preventDefault();const data=new FormData(e.target);try{await api('/api/admin/notifications',{method:'POST',body:JSON.stringify({label:data.get('label'),config:notificationConfig(e.target)})});msg('#notificationMessage','Notification destination added. Use Test to verify it.');e.target.reset();renderNotificationFields();loadNotifications()}catch(x){msg('#notificationMessage',x.message,true)}}
async function loadNotifications(){try{const d=await api('/api/admin/notifications');$('#notificationDestinations').innerHTML=d.destinations.map(n=>`<tr><td><b>${esc(n.label)}</b><br><small>${esc(n.type.replaceAll('_',' '))}</small>${n.last_error?`<br><small class="open">${esc(n.last_error)}</small>`:''}</td><td><button class="secondary ${n.enabled?'resolved':''}" onclick="toggleNotification('${esc(n.id)}',${!n.enabled})">${n.enabled?'Enabled':'Disabled'}</button></td><td>${n.last_sent_at?new Date(n.last_sent_at).toLocaleString():'Never'}</td><td><button class="secondary" onclick="openNotificationEditor('${esc(n.id)}')">Edit</button> <button class="secondary" onclick="testNotification('${esc(n.id)}')">Test</button> <button class="secondary" onclick="deleteNotification('${esc(n.id)}')">Delete</button></td></tr>`).join('')||'<tr><td colspan="4">No notification destinations configured.</td></tr>'}catch(x){msg('#notificationMessage',x.message,true)}}
window.openNotificationEditor=async id=>{try{const d=await api('/api/admin/notifications/'+id),form=$('#editNotificationForm');form.dataset.id=id;$('#editNotificationLabel').value=d.label;$('#editNotificationType').value=d.type;$('#editProvider').textContent=d.type.replaceAll('_',' ');$('#editNotificationFields').innerHTML=notificationFieldTemplates[d.type];for(const [key,value]of Object.entries(d.config)){const field=form.elements.namedItem(key);if(!field)continue;if(field.type==='checkbox')field.checked=Boolean(value);else field.value=value}for(const key of d.secretFields){const field=form.elements.namedItem(key);if(field){field.required=false;field.value='';field.placeholder='Leave blank to keep the existing encrypted value'}}$('#editNotificationMessage').innerHTML='';openModal('#notificationModal')}catch(x){msg('#notificationMessage',x.message,true)}};window.closeNotificationEditor=()=>closeModal('#notificationModal');
async function saveNotification(e){e.preventDefault();const form=e.target;try{await api('/api/admin/notifications/'+form.dataset.id,{method:'PUT',body:JSON.stringify({label:form.elements.namedItem('label').value,config:notificationConfig(form)})});closeNotificationEditor();msg('#notificationMessage','Notification destination updated.');loadNotifications()}catch(x){msg('#editNotificationMessage',x.message,true)}}
window.toggleNotification=async(id,enabled)=>{await api('/api/admin/notifications/'+id,{method:'PATCH',body:JSON.stringify({enabled})});loadNotifications()};window.testNotification=async id=>{try{await api('/api/admin/notifications/'+id+'/test',{method:'POST'});msg('#notificationMessage','Test notification sent.');loadNotifications()}catch(x){msg('#notificationMessage',x.message,true);loadNotifications()}};window.deleteNotification=async id=>{if(!confirm('Delete this notification destination?'))return;await api('/api/admin/notifications/'+id,{method:'DELETE'});loadNotifications()};
boot();
